  json: {
    anthropicApiKey: 'REPLACE_WITH_YOUR_ANTHROPIC_API_KEY',
    anthropicModel: 'REPLACE_WITH_YOUR_ANTHROPIC_MODEL',
    githubToken: 'REPLACE_WITH_YOUR_GITHUB_FINE_GRAINED_PAT',
    githubOwner: 'REPLACE_WITH_YOUR_GITHUB_USERNAME',
    githubRepo: 'REPLACE_WITH_YOUR_REPO_NAME',
    githubBranch: 'main',
    githubPath: 'data/thoughts.json'
  }
}];

const response = $input.first().json;
const content = Array.isArray(response.content) ? response.content : [];
const firstTextBlock = content.find((item) => item.type === 'text');
const thought = (firstTextBlock?.text || '').replace(/^"|"$/g, '').trim();

if (!thought) {
  throw new Error('Anthropic generation returned empty thought text.');
}

return [{ json: { thought } }];

const thought = $input.first().json.thought;
const anthropicModel = $node['Config'].json.anthropicModel;

return [{
  json: {
    thought,
    requestBody: {
      model: anthropicModel,
      max_tokens: 220,
      temperature: 0,
      system: `You are a strict literary editor reviewing short philosophical prose for originality, clarity, and tone.

Judge the text using these standards:
- original rather than derivative
- concrete rather than vague
- thoughtful rather than motivational
- precise rather than bloated
- unresolved in an interesting way rather than neatly concluded

Reject anything that sounds like:
- advice
- a slogan
- a tweet-sized life lesson
- filler dressed up as depth
- generic AI quote writing

Return valid JSON only in this shape:
{
  "approved": true,
  "score": 0,
  "reason": "",
  "suggestion": ""
}

Rules:
- approved must be true only if the text is strong enough to publish unchanged
- score must be an integer from 1 to 10
- reason should be brief
- suggestion should be empty if approved is true`,
      messages: [
        {
          role: 'user',
          content: `Review this thought for publication:\n\n${thought}`
        }
      ]
    }
  }
}];

const response = $input.first().json;
const content = Array.isArray(response.content) ? response.content : [];
const firstTextBlock = content.find((item) => item.type === 'text');
const raw = (firstTextBlock?.text || '').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  parsed = {
    approved: false,
    score: 0,
    reason: 'Review response was not valid JSON.',
    suggestion: raw
  };
}

return [{
  json: {
    approved: Boolean(parsed.approved),
    score: Number(parsed.score || 0),
    reason: parsed.reason || '',
    suggestion: parsed.suggestion || ''
  }
}];

const item = $input.first().json;

if (!item.approved || item.score < 8) {
  return [];
}

return [{ json: item }];

const item = $input.first().json;

const now = new Date();
const kolkataParts = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Kolkata',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
}).formatToParts(now).reduce((acc, part) => {
  if (part.type !== 'literal') acc[part.type] = part.value;
  return acc;
}, {});

const id = `${kolkataParts.year}${kolkataParts.month}${kolkataParts.day}-${kolkataParts.hour}${kolkataParts.minute}${kolkataParts.second}`;
const timestamp = `${kolkataParts.year}-${kolkataParts.month}-${kolkataParts.day}T${kolkataParts.hour}:${kolkataParts.minute}:${kolkataParts.second}+05:30`;

const rawContent = (item.content || '').replace(/\n/g, '');
const decoded = Buffer.from(rawContent, 'base64').toString('utf8');
const parsed = JSON.parse(decoded);
const thoughts = Array.isArray(parsed.thoughts) ? parsed.thoughts : [];

thoughts.unshift({
  id,
  text: item.thought,
  timestamp
});

const updated = {
  thoughts
};

const encoded = Buffer.from(JSON.stringify(updated, null, 2) + '\n', 'utf8').toString('base64');

return [{
  json: {
    thought: item.thought,
    commitBody: {
      message: `Add thought ${id}`,
      content: encoded,
      sha: item.sha,
      branch: $node['Config'].json.githubBranch
    }
  }
}];
